<?php header('Content-Type: application/json; charset=utf-8'); header('X-Content-Type-Options: nosniff'); if($_SERVER['REQUEST_METHOD']!=='POST'){echo json_encode(['success'=>false,'message'=>'Método no permitido.']); exit;} require_once __DIR__.'/config.php'; if(!empty($_POST['website']??'')){echo json_encode(['success'=>true,'message':'Gracias.']); exit;} $name=trim($_POST['name']??''); $email=trim($_POST['email']??''); $phone=trim($_POST['phone']??''); $message=trim($_POST['message']??''); $consentRaw=$_POST['consent']??null; $consent=isset($consentRaw)&&in_array(strtolower((string)$consentRaw),['1','on','true','yes'],true); if($name===''||$email===''||$message===''){echo json_encode(['success'=>false,'message'=>'Por favor completa los campos obligatorios.']); exit;} if(!filter_var($email,FILTER_VALIDATE_EMAIL)){echo json_encode(['success'=>false,'message'=>'El correo no es válido.']); exit;} if(!$consent){echo json_encode(['success'=>false,'message'=>'Debes aceptar ser contactado.']); exit;} $clean=fn($v)=>htmlspecialchars($v,ENT_QUOTES|ENT_SUBSTITUTE,'UTF-8'); $name=$clean($name); $email=$clean($email); $phone=$clean($phone); $message=$clean($message); $to=TO_EMAIL; $subject='Nuevo contacto desde '.SITE_NAME; $body="Nombre: {$name}\nCorreo: {$email}\nTeléfono: {$phone}\n\nMensaje:\n{$message}\n\nIP: ".$_SERVER['REMOTE_ADDR']; $headers=['MIME-Version: 1.0','Content-type: text/plain; charset=utf-8','From: '.FROM_EMAIL,'Reply-To: '.$email]; $sent=@mail($to,$subject,$body,implode("\r\n",$headers)); echo json_encode($sent?['success'=>true,'message'=>'¡Gracias! Tu mensaje fue enviado correctamente.']:['success'=>false,'message'=>'No se pudo enviar el mensaje (mail deshabilitado). Configura SMTP o revisa el servidor.']);